class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        int n = nums.length;
        int m = queries.length;
        long[] answer = new long[m];
        long sum = 0;
        for (int num : nums) {
            sum += num;
        }
        boolean[] marked = new boolean[n];
        int[][] numIndices = new int[n][2];
        for (int i = 0; i < n; i++) {
            numIndices[i][0] = nums[i];
            numIndices[i][1] = i;
        }
        Arrays.sort(numIndices, (a, b) -> a[0] == b[0] ? a[1] - b[1] : a[0] - b[0]);
        int pointer = 0;
        for (int i = 0; i < m; i++) {
            int index = queries[i][0];
            int k = queries[i][1];
            if (!marked[index]) {
                marked[index] = true;
                sum -= nums[index];
            }
            while (k > 0 && pointer < n) {
                if (!marked[numIndices[pointer][1]]) {
                    marked[numIndices[pointer][1]] = true;
                    sum -= numIndices[pointer][0];
                    k--;
                }
                pointer++;
            }
            answer[i] = sum;
        }
        return answer;
    }
}
